def has_body_headers(request: Request) -> bool:
    """
    Return True if the given request contains headers that indicate a body.

    Specifically, this checks for the presence of either a "content-length" or
    a "transfer-encoding" header (case-insensitive).
    """
    return any(
        k.lower() == b"content-length" or k.lower() == b"transfer-encoding"
        for k, v in request.headers
    )


class HTTPConnectionState(enum.IntEnum):
    ACTIVE = 1
    IDLE = 2
    CLOSED = 3


class AsyncHTTP2Connection(AsyncConnectionInterface):
    READ_NUM_BYTES = 64 * 1024
    CONFIG = h2.config.H2Configuration(validate_inbound_headers=False)

    def __init__(
        self,
        origin: Origin,
        stream: AsyncNetworkStream,
        keepalive_expiry: float | None = None,
    ):
        """
        Initialize a new AsyncHTTP2Connection.

        Parameters:
        - origin: The Origin this connection is associated with.
        - stream: The underlying AsyncNetworkStream for network I/O.
        - keepalive_expiry: Optional keepalive expiry timestamp (seconds since the epoch).
        """
        self._origin = origin
        self._network_stream = stream
        self._keepalive_expiry: float | None = keepalive_expiry
        self._h2_state = h2.connection.H2Connection(config=self.CONFIG)
        self._state = HTTPConnectionState.IDLE
        self._expire_at: float | None = None
        self._request_count = 0
        self._init_lock = AsyncLock()
        self._state_lock = AsyncLock()
        self._read_lock = AsyncLock()
        self._write_lock = AsyncLock()
        self._sent_connection_init = False
        self._used_all_stream_ids = False
        self._connection_error = False

        # Mapping from stream ID to response stream events.
        self._events: dict[
            int,
            list[
                h2.events.ResponseReceived
                | h2.events.DataReceived
                | h2.events.StreamEnded
                | h2.events.StreamReset,
            ],
        ] = {}

        # Connection terminated events are stored as state since
        # we need to handle them for all streams.
        self._connection_terminated: h2.events.ConnectionTerminated | None = None

        self._read_exception: Exception | None = None
        self._write_exception: Exception | None = None

    def can_handle_request(self, origin: Origin) -> bool:
        """
        Return True if this connection can handle a request to the given origin.

        A connection can handle the request if the origin matches the connection's
        origin and the connection is not closed.
        """
        if origin is None:
            return False
        return origin == self._origin and self._state != HTTPConnectionState.CLOSED

    def is_available(self) -> bool:
        """
        Return True if the connection can currently be used for sending requests.

        A connection is available if it is not in the CLOSED state and no fatal
        connection error has been recorded.
        """
        return self._state != HTTPConnectionState.CLOSED and not self._connection_error

    def has_expired(self) -> bool:
        """
        Return True if this connection has expired according to its keepalive timer.

        If an explicit expire_at timestamp is set, that takes precedence; otherwise
        the keepalive_expiry provided at construction is used.
        """
        now = time.time()
        if self._expire_at is not None:
            return now >= self._expire_at
        if self._keepalive_expiry is not None:
            return now >= self._keepalive_expiry
        return False

    def is_idle(self) -> bool:
        """
        Return True if this connection is currently idle.

        Idle means the connection is not actively processing a request.
        """
        return self._state == HTTPConnectionState.IDLE

    def is_closed(self) -> bool:
        """
        Return True if this connection has been closed.
        """
        return self._state == HTTPConnectionState.CLOSED

    def info(self) -> dict[str, typing.Any]:
        """
        Return a small dictionary of human-readable information about the connection.

        This is useful for debugging, logging, and connection pool management.
        """
        return {
            "origin": self._origin,
            "state": self._state.name,
            "request_count": self._request_count,
            "expire_at": self._expire_at,
            "keepalive_expiry": self._keepalive_expiry,
            "connection_error": self._connection_error,
        }

    def __repr__(self) -> str:
        """
        Return a compact string representation of the connection state.
        """
        return (
            f"<AsyncHTTP2Connection origin={self._origin!r} state={self._state.name} "
            f"requests={self._request_count}>"
        )


class HTTP2Stream:
    def __init__(self, stream_id: int, connection: AsyncHTTP2Connection):
        """
        Represents a single HTTP/2 stream within a connection.

        Parameters:
        - stream_id: The numeric stream identifier in the HTTP/2 connection.
        - connection: The AsyncHTTP2Connection that owns this stream.
        """
        self.stream_id = stream_id
        self.connection = connection
        self.events: list[h2.events.Event] = []
        self.closed = False

    def add_event(self, event: h2.events.Event) -> None:
        """Add an event to this stream's event list."""
        self.events.append(event)

    def close(self) -> None:
        """Mark this stream as closed."""
        self.closed = True